def _gen_math_mult(a: int, b: int) -> tuple:
    """Генерирует вопрос на умножение a×b."""
    ans = a * b
    opts = [ans - 2, ans - 1, ans, ans + 1] if ans > 2 else [ans, ans + 1, ans + 2, ans + 3]
    opts = list(dict.fromkeys(opts))[:4]
    if ans not in opts:
        opts[0] = ans
    idx = opts.index(ans)
    return ("математика", "easy", "Арифметика", "Арифметика",
            f"Чему равно {a} × {b}?", f"{a} × {b} неге тең?",
            [str(x) for x in opts], [str(x) for x in opts], idx,
            f"{a} × {b} = {ans}.", f"{a} × {b} = {ans}.")


# Генерируемые вопросы (уникальные формулировки)
_GEN_MULT = [(a, b) for a in range(4, 25) for b in range(4, 25) if a <= b and a * b < 300][:280]
GENERATED = [_gen_math_mult(a, b) for a, b in _GEN_MULT]


def _gen_math_div(a: int, b: int) -> tuple:
    """Вопрос: a ÷ b = ? (b делит a)."""
    ans = a // b
    opts = [ans - 1, ans, ans + 1, ans + 2]
    opts = [x for x in opts if x > 0][:4]
    if ans not in opts:
        opts = [ans, ans + 1, ans + 2, ans + 3][:4]
    idx = opts.index(ans) if ans in opts else 0
    return ("математика", "easy", "Арифметика", "Арифметика",
            f"Чему равно {a} ÷ {b}?", f"{a} ÷ {b} неге тең?",
            [str(x) for x in opts], [str(x) for x in opts], idx,
            f"{a} ÷ {b} = {ans}.", f"{a} ÷ {b} = {ans}.")


_GEN_DIV = [(a, b) for a in range(12, 200, 6) for b in [2, 3, 4, 5, 6, 8, 10, 12] if a % b == 0][:150]
GENERATED += [_gen_math_div(a, b) for a, b in _GEN_DIV]


def _gen_math_add(a: int, b: int) -> tuple:
    """Вопрос: a + b = ?"""
    ans = a + b
    opts = [ans - 2, ans - 1, ans, ans + 1]
    opts = list(dict.fromkeys([x for x in opts if x > 0]))[:4]
    if ans not in opts:
        opts = [ans, ans + 1, ans + 2, ans - 1][:4]
    idx = opts.index(ans) if ans in opts else 0
    return ("математика", "easy", "Арифметика", "Арифметика",
            f"Чему равно {a} + {b}?", f"{a} + {b} неге тең?",
            [str(x) for x in opts], [str(x) for x in opts], idx,
            f"{a} + {b} = {ans}.", f"{a} + {b} = {ans}.")


_GEN_ADD = [(a, b) for a in range(15, 100) for b in range(10, 60) if a + b < 140][:200]
GENERATED += [_gen_math_add(a, b) for a, b in _GEN_ADD]


def _gen_math_sub(a: int, b: int) -> tuple:
    """Вопрос: a - b = ? (a > b)"""
    ans = a - b
    opts = [ans - 1, ans, ans + 1, ans + 2]
    opts = [x for x in opts if x > 0][:4]
    if ans not in opts:
        opts = [ans, ans + 1, ans + 2, ans + 3][:4]
    idx = opts.index(ans) if ans in opts else 0
    return ("математика", "easy", "Арифметика", "Арифметика",
            f"Чему равно {a} - {b}?", f"{a} - {b} неге тең?",
            [str(x) for x in opts], [str(x) for x in opts], idx,
            f"{a} - {b} = {ans}.", f"{a} - {b} = {ans}.")


_GEN_SUB = [(a, b) for a in range(30, 120) for b in range(10, 50) if a > b and a - b < 100][:150]
GENERATED += [_gen_math_sub(a, b) for a, b in _GEN_SUB]


def _gen_math_pct(pct: int, num: int) -> tuple:
    """Вопрос: pct% от num = ?"""
    ans = num * pct // 100
    opts = [ans - 5, ans - 2, ans, ans + 2]
    opts = list(dict.fromkeys([x for x in opts if x >= 0]))[:4]
    if ans not in opts:
        opts = [ans, ans + 1, ans + 5, ans + 10][:4]
    idx = opts.index(ans) if ans in opts else 0
    return ("математика", "medium", "Проценты", "Пайыз",
            f"Сколько будет {pct}% от {num}?", f"{num}-тың {pct}%-ы неше?",
            [str(x) for x in opts], [str(x) for x in opts], idx,
            f"{pct}% от {num} = {ans}.", f"{num}-тың {pct}%-ы = {ans}.")


_GEN_PCT = [(p, n) for p in [5, 10, 15, 20, 25, 30, 40, 50, 60, 75] for n in range(40, 200, 10)][:120]
GENERATED += [_gen_math_pct(p, n) for p, n in _GEN_PCT]


def _gen_alg_solve_lin(k: int, b: int, c: int) -> tuple:
    """Решите: kx + b = c. Ответ x = (c-b)/k."""
    if k == 0 or (c - b) % k != 0:
        return None
    ans = (c - b) // k
    opts = [ans - 2, ans - 1, ans, ans + 1]
    opts = list(dict.fromkeys(opts))[:4]
    if ans not in opts:
        opts[0] = ans
    idx = opts.index(ans)
    return ("алгебра", "medium", "Уравнения", "Теңдеулер",
            f"Решите: {k}x + {b} = {c}", f"Шешіңіз: {k}x + {b} = {c}",
            [f"x = {x}" for x in opts], [f"x = {x}" for x in opts], idx,
            f"{k}x = {c-b}, x = {ans}.", f"{k}x = {c-b}, x = {ans}.")


_GEN_LIN = []
for k in [2, 3, 4, 5]:
    for b in range(1, 15):
        for c in range(b + k, b + 8 * k, k):
            t = _gen_alg_solve_lin(k, b, c)
            if t and len(_GEN_LIN) < 150:
                _GEN_LIN.append(t)
GENERATED += _GEN_LIN


def _gen_geom_pythag(a: int, b: int) -> tuple:
    """Катеты a и b. Гипотенуза?"""
    import math
    c = int(math.sqrt(a * a + b * b))
    if c * c != a * a + b * b:
        return None
    opts = [c - 1, c, c + 1, c + 2]
    opts = list(dict.fromkeys([x for x in opts if x > 0]))[:4]
    if c not in opts:
        opts[0] = c
    idx = opts.index(c)
    return ("геометрия", "medium", "Теорема Пифагора", "Пифагор теоремасы",
            f"Катеты {a} и {b}. Чему равна гипотенуза?", f"Катеттер {a} және {b}. Гипотенуза неге тең?",
            [str(x) for x in opts], [str(x) for x in opts], idx,
            f"c² = {a}² + {b}² = {c}².", f"c² = {a}² + {b}² = {c}².")


_GEN_PYTH = []
for a in range(3, 20):
    for b in range(a, 25):
        t = _gen_geom_pythag(a, b)
        if t and len(_GEN_PYTH) < 80:
            _GEN_PYTH.append(t)
GENERATED += _GEN_PYTH


def _gen_bin_to_dec(bin_str: str) -> tuple:
    """Двоичное число bin_str в десятичной?"""
    ans = int(bin_str, 2)
    opts = [ans - 2, ans - 1, ans, ans + 1]
    opts = list(dict.fromkeys([x for x in opts if x >= 0]))[:4]
    if ans not in opts:
        opts[0] = ans
    idx = opts.index(ans)
    return ("информатика", "easy", "Системы счисления", "Санау жүйелері",
            f"Чему равно {bin_str}₂ в десятичной системе?", f"{bin_str}₂ ондық жүйеде неге тең?",
            [str(x) for x in opts], [str(x) for x in opts], idx,
            f"{bin_str}₂ = {ans}.", f"{bin_str}₂ = {ans}.")


_GEN_BIN = []
for n in range(8, 256):
    b = bin(n)[2:]
    if len(b) >= 4 and len(_GEN_BIN) < 100:
        _GEN_BIN.append(_gen_bin_to_dec(b))
GENERATED += _GEN_BIN


def _gen_power(base: int, exp: int) -> tuple:
    """Чему равно base^exp?"""
    ans = base ** exp
    opts = [ans - 1, ans, ans + 1, ans + base]
    opts = list(dict.fromkeys([x for x in opts if x > 0]))[:4]
    if ans not in opts:
        opts[0] = ans
    idx = opts.index(ans)
    return ("алгебра", "easy", "Степени", "Дәрежелер",
            f"Чему равно {base}^{exp}?", f"{base}^{exp} неге тең?",
            [str(x) for x in opts], [str(x) for x in opts], idx,
            f"{base}^{exp} = {ans}.", f"{base}^{exp} = {ans}.")


_GEN_POW = []
for base in [2, 3, 4, 5, 6]:
    for exp in range(2, 9):
        if base ** exp < 10000 and len(_GEN_POW) < 120:
            _GEN_POW.append(_gen_power(base, exp))
GENERATED += _GEN_POW


def _gen_dec_to_bin(n: int) -> tuple:
    """Как записывается n в двоичной системе?"""
    ans = bin(n)[2:]
    wrong = [bin(n + 1)[2:], bin(n - 1)[2:] if n > 1 else "0", bin(n + 2)[2:], bin(n)[2:][::-1]]
    opts = list(dict.fromkeys([ans] + [w for w in wrong if w != ans]))[:4]
    idx = opts.index(ans)
    return ("информатика", "easy", "Системы счисления", "Санау жүйелері",
            f"Как записывается число {n} в двоичной системе?", f"{n} саны екілік жүйеде қалай жазылады?",
            opts, opts, idx, f"{n}₁₀ = {ans}₂.", f"{n}₁₀ = {ans}₂.")


_GEN_DEC2BIN = [_gen_dec_to_bin(n) for n in range(10, 128) if len(bin(n)[2:]) >= 4][:80]
GENERATED += _GEN_DEC2BIN

# Объединяем
BATCH = BATCH + GENERATED
